      let n = session;
      const voteResult1 = await interpret(consensusHandler.vote({ session: n, agent_id: "a1", position: "approach_A", confidence: 0.8, reasoning: "Better coverage" }), storage);
      expect(voteResult1.variant).toBe("ok");
